package com.oneil.wellness.walkplanner.data;import com.oneil.wellness.walkplanner.activity.*;import com.oneil.wellness.walkplanner.history.*;import java.time.*;import java.util.Set;import org.slf4j.*;import org.springframework.scheduling.annotation.Scheduled;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service public class HistoryRetentionService{private static final Logger log=LoggerFactory.getLogger(HistoryRetentionService.class);private static final Set<Integer> SUPPORTED=Set.of(30,90,180,365);private final HistoryRetentionRepository settings;private final HistoryRepository history;private final WalkActivityRepository activities;private final OpportunityOutcomeRepository outcomes;private final NotificationDeliveryRepository notifications;public HistoryRetentionService(HistoryRetentionRepository s,HistoryRepository h,WalkActivityRepository a,OpportunityOutcomeRepository o,NotificationDeliveryRepository n){settings=s;history=h;activities=a;outcomes=o;notifications=n;}public HistoryRetention current(){return settings.findById((short)1).orElseGet(()->new HistoryRetention(new HistoryRetentionRequest(90,90,90,null)));}@Transactional public HistoryRetention save(HistoryRetentionRequest r){validate(r);HistoryRetention v=settings.findById((short)1).orElseGet(()->new HistoryRetention(r));v.update(r);return settings.save(v);}@Scheduled(cron="${history.retention.cleanup-cron:0 17 3 * * *}")@Transactional public void cleanup(){HistoryRetention r=current();Instant now=Instant.now();var recommendations=r.getRecommendationDays()==null?java.util.List.<RecommendationHistory>of():history.findTop500ByCapturedAtBeforeOrderByCapturedAtAsc(now.minus(Duration.ofDays(r.getRecommendationDays())));var deliveries=r.getNotificationDays()==null?java.util.List.<NotificationDelivery>of():notifications.findTop500ByDeliveredAtBeforeOrderByDeliveredAtAsc(now.minus(Duration.ofDays(r.getNotificationDays())));var expired=r.getExpiredOutcomeDays()==null?java.util.List.<OpportunityOutcome>of():outcomes.findTop500ByStatusAndRecordedAtBeforeOrderByRecordedAtAsc(ActivityStatus.EXPIRED,now.minus(Duration.ofDays(r.getExpiredOutcomeDays())));var walkRows=r.getActivityDays()==null?java.util.List.<WalkActivity>of():activities.findTop500ByOpportunityStartBeforeOrderByOpportunityStartAsc(OffsetDateTime.ofInstant(now.minus(Duration.ofDays(r.getActivityDays())),ZoneOffset.UTC));history.deleteAllInBatch(recommendations);notifications.deleteAllInBatch(deliveries);outcomes.deleteAllInBatch(expired);activities.deleteAllInBatch(walkRows);log.info("History retention cleanup recommendations={} notifications={} expiredOutcomes={} activities={}",recommendations.size(),deliveries.size(),expired.size(),walkRows.size());}private void validate(HistoryRetentionRequest r){if(r==null)throw new IllegalArgumentException("Retention settings are required.");for(Integer v:new Integer[]{r.recommendationDays(),r.notificationDays(),r.expiredOutcomeDays(),r.activityDays()})if(v!=null&&!SUPPORTED.contains(v))throw new IllegalArgumentException("Retention must be 30, 90, 180, 365 days, or indefinite.");}}
